var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"아, 진짜. 옷에 구멍 숭숭 뚫렸잖아.","JPN":"ったく。服に穴が開いたじゃない。","ENG":"Oh, man. My clothes have holes now.","TWN":"吼唷，討厭，衣服都破了啦！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"모처럼 받은 의뢰라 신경 좀 썼더니…….","JPN":"せっかく受けた依頼だから気合入れてきたのに……","ENG":"All I wanted was to do my best to accomplish the task...","TWN":"想說好不容易才接到委託，還特地打扮一下……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그나저나 어제 그 녀석들, 길바닥에 굴러다니는 허접들에 비하면 실력이 꽤 좋았단 말이지.","JPN":"そういや昨日のやつら、そこらに転がっている底辺どもに比べたら実力はある方だったな。","ENG":"By the way, those new girls were pretty good, compared to other idiots.","TWN":"不過，昨天那些傢伙，不像其他的二百五，好像滿會打的。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"묘하게 침식체가 아니라 사람이랑 더 많이 싸워 본 것 같던데…….","JPN":"妙に侵食体じゃなくて、人と戦った経験の方が豊富そうだったけど……","ENG":"They seemed more proficient in fighting humans than C.O.s...","TWN":"只是有點奇妙，他們戰鬥的對象好像比較多是人，而不是侵蝕體……"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"코핀 컴퍼니가 불렀나? 아니면 설마 그 촌뜨기들이?","JPN":"コフィンカンパニーが呼んだのかな？　それともまさかあの田舎者たちが？","ENG":"Did the Coffin Company summon them? Or those hillbillies?","TWN":"是科芬公司找來的嗎？還是那些土包子？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"흥. 뭐 어때. 어차피 오늘이면 이 지겨운 의뢰랑도 작별일 텐데.","JPN":"ふーん、まあいいや。どうせ今日でこのうんざりする依頼ともお別れだし。","ENG":"Hmpf, whatever. This dreadful contract will be over today.","TWN":"哼，不管啦！反正今天就是要把這個討厭的委託給結束掉！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"돌아가는 대로 완수금으로 새로운 배나 한 척 뽑아야지.","JPN":"戻ったら完遂金で新しい船でも一隻買おっと。","ENG":"I’ll buy a new ship as soon as I get the money.","TWN":"我回去要立刻用委託金買一艘新的船！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"최신 사양의 럭셔리 보트로 말이야. 캬하핫!","JPN":"最新仕様のラグジュアリーボートだ、キャハハッ！","ENG":"The most expensive one. Kya hah hah!","TWN":"而且還是全新豪華配備版的遊艇，哇哈哈哈！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"후후……. 후후훗…….","JPN":"ふふ……ふふふっ……","ENG":"Heh heh... Heh heh heh...","TWN":"呵呵… 呵呵呵…"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"나 왔어, 박사님.","JPN":"戻ったぞ、博士。","ENG":"Hey, doctor.","TWN":"博士，我來囉～"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"박사님이 이번에 새로 만든 침식체들, 효과 끝내 주더라?","JPN":"博士が今回新しく作った侵食体、最高だったよ。","ENG":"Your new C.O.s did great!","TWN":"博士這次新做的侵蝕體效果超棒欸！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"의뢰주한테서 오늘 일 끝나면 풀어 주라고 확답 받았어. 진즉 이랬으면 좋았잖아.","JPN":"依頼主から今日の仕事が終わったら解放してやれと確答されたよ。博士もさっさとこうしとけばよかったのにな。","ENG":"The client told me to let you go once the job is finished today. You should have done it sooner, doctor.","TWN":"委託人保證說，只要今天把事情搞定，就會放了你，是不是很棒？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그래요. 처음부터 이래야 했어요.","JPN":"そうです。最初からこうするべきでした。","ENG":"Yes, I should have done this sooner.","TWN":"沒錯，一開始就該這樣！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"휴양지에 바퀴벌레처럼 기어들어 올 커플들에게…… 잊지 못할 휴가를 선사해 주기 위해.","JPN":"リゾート地にゴキブリのごとく集まってきたカップルたちに……一生忘れられないバカンスの思い出を作らせるために。","ENG":"I should have given all these disgustingly lovely couples on the beach... a nightmarish vacation...","TWN":"那些像蟑螂一樣潛入度假村情侶…我要送你們一個難忘的假期。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"응……?","JPN":"え……？","ENG":"Huh?","TWN":"嗯…？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"내가 잘못 들었나? 갑자기 왜 안 하던 헛소리를 하고 그래?","JPN":"あたしの聞き間違い？　急にどういうこと？","ENG":"What did you say? What the heck are you talking about?","TWN":"我有聽錯嗎？你在跟我雞同鴨講嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"맞아요. 한동안은 저 자신을 속이고 살았어요.","JPN":"そうです。しばらくの間、私は自分自身を騙してきました。","ENG":"Yes. I’ve been fooling myself for too long.","TWN":"沒錯，過去我一直在欺騙自己。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"하지만 새로운 침식체들을 만들면서 깨달았어요. 제가 여기서 뭘 해야 되는지.","JPN":"しかし、新しい侵食体を作りながら悟りました。私がここで何をすればいいのか。","ENG":"But when I was making new C.O.s, I found my calling.","TWN":"但是在做新的侵蝕體時，我突然恍然大悟！我到底要在這裡做什麼！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭔데? 어차피 들어서 좋을 것 없는 헛소리겠지만.","JPN":"何すんの？　どうせろくでもない話だろうけど。","ENG":"And what would that be? I suppose it’s more bullcrap though.","TWN":"說什麼呢？反正應該不重要吧！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"사랑 같이 허울 좋은 소리에 취해 있는 이 세상에 각성을 촉구하는 겁니다.","JPN":"愛のような見せかけの言葉に酔っているこの世界に覚醒を促すのです。","ENG":"I have to help the world open its eyes and face the lie—the lie of love.","TWN":"我要讓在愛情海裡載浮載沉的人清醒過來！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"바로 충격과 공포로 말이죠.","JPN":"衝撃と恐怖で。","ENG":"With shock and awe.","TWN":"利用衝擊和恐懼。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"박사님 미쳤어?","JPN":"博士、頭大丈夫？","ENG":"Have you gone nuts?","TWN":"博士，有病要看醫生。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"마음대로 생각해요. 장님뿐인 나라에서는 두 눈 멀쩡한 사람이 미치광이니까.","JPN":"信じるかどうかは自由に。愚者しかいない国では、悟った人間が狂人扱いを受けるものですから。","ENG":"I don’t care what you think. In the blind man’s world, those who can see are called crazy.","TWN":"你才有病，你全家都有病！！反正在這個世界裡，跟人家與眾不同的人就是有病！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"하지만……. 당신도 조만간 생각을 바꾸게 될 걸요.","JPN":"でも……あなたもすぐに納得するでしょう。","ENG":"But... you’ll soon open your eyes.","TWN":"不過……你遲早也會改變想法的。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"이번에야말로 완성할 테니까! 내 평생의 원한을 대신 풀어 줄 역작을!","JPN":"今度こそ完成させるから！　私の一生の恨みを晴らしてくれる力作を！","ENG":"I’m going to finish my task this time. The masterpiece that will realize my lifelong wish!","TWN":"終於要完成啦！可以替我報仇的曠世傑作！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"아하하하하하하!","JPN":"アハハハハハ！","ENG":"Ah hah hah hah hah!","TWN":"哇哈哈哈哈哈哈！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"햇볕을 너무 오래 안 봐서 맛이 갔나…….","JPN":"長い間太陽の光に当たってないから、とうとうイカれちまったのか……","ENG":"I guess she’s been in this dungeon for too long...","TWN":"是關在這裡太久，頭殼壞掉了嗎……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"리조트에다 의사 한 명 불러 달라고 연락해 줄게. 박사님.","JPN":"リゾートに医者を一人呼んでほしいと連絡してやるよ、博士。","ENG":"I’ll ask the resort to send a doctor for you.","TWN":"我會請度假村幫你找醫生。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"만나서 즐거웠고, 앞으로 두 번 다시 보지 말자.","JPN":"会えてよかったぜ。二度と会わないことを祈るけど。","ENG":"It’s been pleasure; I hope I never see you again.","TWN":"這段時間很開心認識你，希望以後不會再見。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"아하하하하하하! 하하하하하……","JPN":"アハハハハハハ！　ハハハハハ……","ENG":"Ah hah hah hah hah! Hah hah hah...","TWN":"哇哈哈哈哈哈哈哈！哈哈哈哈…"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":" 콜록! 콜록! 케흑!","JPN":"ゴホッ！　ゴホッ！　ゲホッ！","ENG":" *Cough, cough!*","TWN":"咳咳！咳咳！咳咳！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"후우……. 가, 갔나?","JPN":"ふう……行ったか？","ENG":"Phew... Is she... gone now?","TWN":"呼… 走…走了嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"간신히 빼돌렸어. 솔로카오로 만든 초콜릿 원액.","JPN":"やっと手に入れた。ソロカオで作ったチョコレート原液。","ENG":"I did it. I skimmed off some chocolate extract made of Solocao.","TWN":"終於從獨株可可中萃取出巧克力原料。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"하지만 겨우 한 번 쓰면 바닥날 분량이야.","JPN":"でも一回しか使えない分量か。","ENG":"It’s barely enough to make one. I have only one chance.","TWN":"但份量只夠使用一次。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"고작 이걸로…… 저 사람을 막을 수 있을까?","JPN":"これだけで……あの人を止められるかな。","ENG":"Will I be able to... stop that woman with this?","TWN":"這樣…能夠攔得住那個人嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"……아냐. 선배님의 응원을 잊어선 안 돼.","JPN":"……いや、先輩の応援を忘れてはいけない。","ENG":"No, Dark said I could do it.","TWN":"…不行，不可以忘記前輩的鼓勵。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"만드는 거야. 선배님도 감탄하실 만한…….","JPN":"作るんだ。先輩も感心するような……","ENG":"I can do it. Even Dark will be impressed when he sees this...","TWN":"我要做出連前輩都會驚嘆的……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"최강의 초콜릿 침식체를……!","JPN":"最強のチョコレート侵食体を……！","ENG":"The ultimate chocolate C.O.!","TWN":"最強巧克力侵蝕體……！"},"stage":{"bg":"SUMMER_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"한 번만 더 재고해 보시죠, 대표님.","JPN":"もう一度考え直してください、社長。","ENG":"You have to reconsider, sir.","TWN":"代表，請再考慮一下。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"……물론 저희가 조금 늦은 건 사실이지만, 아직 기한이 남았잖습니까.","JPN":"もちろん俺たちが多少遅れたのは事実ですが、まだ期限が残っているじゃないですか。","ENG":"... Yes, I know we’re running a bit late, but we haven’t met the deadline yet.","TWN":"……我們確實是進度落後，但期限又還沒到。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"맡겨 두십시오. 그 녀석을 쓰시기 전에 전부 해결하고 연락드리겠습니다.","JPN":"任せておいてください。あいつを使う前に全て解決して、また連絡します。","ENG":"Have faith in us. We’ll take care of it without using the device.","TWN":"包在我們身上！我們會在在使用那個東西之前，就會先把事情搞定，事成後再通知您。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"젠장, 대체 어떤 정신 나간 손님이 멀쩡한 마을 갖고 그딴 클레임을 넣은 거야.","JPN":"ちぇっ、いったいどんな頭がおかしい客が普通の村にあんなクレームを入れたんだ。","ENG":"Darn it, what kind of idiots file complaints against such a fine village like that?","TWN":"該死的，到底是哪個神經病沒事投訴村莊破壞景色啦！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PMC_SUMMER_NULL_NULL","text":{"KOREA":"대장님. 정찰조 지금 막 복귀했습니다.","JPN":"隊長。偵察班が只今戻りました。","ENG":"Leader, the scouts are back.","TWN":"隊長，巡邏組回來了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"그래. 감시하느라 수고했다.","JPN":"ああ。見張り、ご苦労さま。","ENG":"Okay, good.","TWN":"很好，巡邏辛苦了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"마을 상황은 어떻지?","JPN":"村の状況はどうだ？","ENG":"How’s the village?","TWN":"現在村裡的狀況如何？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PMC_SUMMER_NULL_NULL","text":{"KOREA":"어제부터 이렇다 할 움직임은 없었습니다.","JPN":"昨日からこれといった動きはありませんでした。","ENG":"Nothing special since yesterday.","TWN":"昨天都沒什麼特別的動靜。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PMC_SUMMER_NULL_NULL","text":{"KOREA":"그동안 있었던 일을 생각하면, 중장비 앞에 드러누워서라도 막으려고 하지 않을까요?","JPN":"これまでのことを考えると、重機の前に横になってでも止めようとするのでは？","ENG":"Considering how they have been reacting so far, they may lie down in front of our heavy machinery to stop us.","TWN":"看他們之前的反應，很可能會躺在怪手前抵死不從吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"그러겠지. 죽고 싶으면 마음대로 하라고 해.","JPN":"そうだな。死にたければ勝手にしろと言うしかない。","ENG":"I suppose. Whatever, it’s their lives, not ours.","TWN":"可能吧，想死就隨便他們。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"PMC_SUMMER_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"でも……","ENG":"But...","TWN":"可是…"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"다 끝난 얘기에 왜 아직도 미련을 가져? 아저씨들 설마 벌써 갱년기야?","JPN":"もう終わった話にいつまで未練を持ってんの？　おっさんたち、まさかもう更年期なわけ？","ENG":"Why do you care about something that’s already decided? Is this some sort of midlife crisis?","TWN":"不是都決定好了嗎？還可是什麼？還是大叔更年期到了？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PMC_SUMMER_NULL_NULL","text":{"KOREA":"뭐? 너 지금 뭐라고 지껄였어?","JPN":"はあ？　お前今なんて言った？","ENG":"What did you say?","TWN":"什麼？你在胡說八道什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L34_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"그만해. 새파랗게 어린 애 상대로.","JPN":"ガキ相手にやめろ。","ENG":"Stop it, she’s just a kid.","TWN":"夠了，跟乳味未乾的小鬼吵什麼！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"드라코, 너도 신경 긁는 소리 적당히 해라.","JPN":"ドラコ、お前もいい加減にしろ。","ENG":"And you, Dracasia, stop with the taunting.","TWN":"德拉克，你也不要一直激怒他們。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L37_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"다들 신경이 곤두서 있어. 오늘은 손에 피를 묻힐지도 모르니까.","JPN":"みんな神経を尖らせている。今日は手を血に染める日になるかもしれないからな。","ENG":"Everyone’s on edge because there might be some blood today.","TWN":"大家繃緊神經，今天很可能會見血。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"<color=#ffd34c>숸에 퓌를 묻휠지도 모르니까~</color>래.","JPN":"<color=#ffd34c>てぇを～ちぃに～そぉめる～</color>なんてね。","ENG":"<color=#ffd34c>Thwere might be some bhlwood todway</color>, hah.","TWN":"<color=#ffd34c>可能會見血~</color>……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":" 개웃기네, 진짜.","JPN":"笑えるわ、マジで。","ENG":" Y’all clowns.","TWN":"有夠好笑！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"우린 기다려 줄 만큼 기다려 줬어. 늙은이들 노후 생활은 알아서들 하라고 해.","JPN":"あたしたちだって十分待ってあげたんだ。爺婆の老後生活なんて知ったこっちゃない。","ENG":"We gave them enough chances. It’s their lives and their choices.","TWN":"我們已經給他們夠多時間了，還管他們見不見血的！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"아저씨들은 남들 인생 챙겨 줄 만큼 세상이 한가해?","JPN":"おっさんたちだって赤の他人に気遣うほどの余裕なんてないっしょ？","ENG":"Don’t you have anything better to do than worrying about these people?","TWN":"你們是不是太閒啦？還有空擔心別人。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PMC_SUMMER_NULL_NULL","text":{"KOREA":"더는 못 참아! 운 좋게 카운터가 된 주제에 뭐 잘났다고 대장님한테 훈계질이야!","JPN":"もう我慢できん！　運良くカウンターになっただけのくせに、なんだその生意気な口の利き方は！","ENG":"I can’t stand it anymore! You only became a Counter by luck. What makes you think you’re better than our leader?","TWN":"我真是忍無可忍！不過就是狗屎運成為制裁者，有什麼了不起？憑什麼對隊長這種態度！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"그만하라고 했잖아! 내 말 안 들리나?!","JPN":"やめろと言ったはずだ！　聞こえないのか！？","ENG":"I said stop! Didn’t you hear me?","TWN":"我不是說夠了嗎！把我的話當耳邊風啊？！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"PMC_SUMMER_NULL_NULL","text":{"KOREA":"……죄, 죄송합니다. 대장.","JPN":"す、すみません、隊長。","ENG":"... I-I’m sorry, leader.","TWN":"…隊…隊長對不起。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"그래, 드라코. 네 말이 맞다는 건 나도 알아.","JPN":"そうだ、ドラコ。お前の言うことは正しい。","ENG":"Yes, Dracasia. I understand what you’re saying.","TWN":"德拉克，你說的沒錯。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"그냥…… 이런 지저분한 짓으로 돈을 벌어야 한다는 게 더럽게 마음에 안 들 뿐이지.","JPN":"俺はただ……こんな汚いことまでして、お金を稼がなければならないという事実がクソほど気に食わないだけだ。","ENG":"Still... I’m not happy doing all this dirty work, just to make some money.","TWN":"只是…我不喜歡用下三濫的手段，賺這種骯髒錢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"다들 차에 올라타! 마을로 출발한다!","JPN":"さあ、みんな車に乗れ！　村へ出発する！","ENG":"Everyone hop on! We’re heading to the village!","TWN":"大家上車吧！出發去村莊！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};